// Verwerk inkomende Facebook comment-events.
// Geeft één item per nieuwe reactie terug; alles anders wordt gefilterd.

const body = $input.first().json.body;

if (!body?.entry?.length) return [];

const items = [];
for (const entry of body.entry) {
  for (const change of (entry.changes ?? [])) {
    const v = change.value;
    // Alleen nieuwe reacties (geen bewerkingen, verwijderingen of likes)
    if (v?.item !== 'comment' || v?.verb !== 'add') continue;

    items.push({ json: {
      postId:        v.post_id,
      commentId:     v.comment_id,
      commenterId:   v.from?.id   ?? '',
      commenterNaam: v.from?.name ?? '',
      tekst:         (v.message  ?? '').trim(),
    }});
  }
}
return items;

