// Controleer of de reactietekst het keyword bevat (case-insensitief).
// Return [] = executie stopt hier (geen DM versturen).

const keyword      = $json.keyword;
const dmTekst      = $json.dmTekst;
const comment      = $('Extraheer Reactie').item.json;

if (!comment.tekst.toLowerCase().includes(keyword.toLowerCase())) {
  return [];
}

return [{ json: {
  commenterId:   comment.commenterId,
  commenterNaam: comment.commenterNaam,
  tekst:         comment.tekst,
  keyword,
  dmTekst,
}}];
